import pytest
import requests

TIER_CASES = [
    (150.00, "basic"),
    (5000.00, "standard"),
    (25000.00, "premium"),
]

@pytest.mark.parametrize("deposit,expected_tier", TIER_CASES)
def test_open_savings_account_tier_assignment_decision_table(deposit, expected_tier, verified_customer_token, api_base_url, cleanup_account):
    headers = {"Authorization": f"Bearer {verified_customer_token}", "Content-Type": "application/json"}
    payload = {"initial_deposit": deposit}

    resp = requests.post(f"{api_base_url}/accounts/savings", json=payload, headers=headers)

    assert resp.status_code == 201, f"Expected 201 for deposit {deposit}, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert body.get("tier") == expected_tier, f"Expected tier '{expected_tier}' for deposit {deposit}, got '{body.get('tier')}'"

    cleanup_account(body["account_id"], headers)
